1	const PROCESSING_FEE = 5;
2	
3	type Item = { type: string; material?: string; enchantment?: number; cursed?: boolean };
4	
5	const CURSE_SURCHARGE = 0.5;
6	const HIGH_ENCHANT_SURCHARGE = 0.3;
7	const HIGH_ENCHANT_THRESHOLD = 5;
8	const LOYALTY_DISCOUNT = 0.2;
9	const LOYALTY_THRESHOLD = 2;
10	const FIRST_INSURANCE_SURCHARGE = 0.1;
11	const FOLLOW_UP_DISCOUNT = 0.15;
12	const DEDUCTIBLE = 100;
13	const HIGH_ENCHANT_PAYOUT_THRESHOLD = 8;
14	const HIGH_ENCHANT_REIMBURSEMENT_RATE = 0.5;
15	const FULL_REIMBURSEMENT_RATE = 1;
16	
17	type Customer = { yearsWithMHPCO: number };
18	type Damage = { itemType: string; amount: number };
19	type Incident = { cause: string; damages: Damage[] };
20	type QuoteStep = { op: "quote"; items: Item[] };
21	type ClaimStep = { op: "claim"; policy: number; incident: Incident };
22	type Step = QuoteStep | ClaimStep;
23	type Scenario = { customer: Customer; steps: Step[] };
24	type QuoteResult = { premium: number };
25	type ClaimResult = { payout: number; remainingCap: number };
26	type StepResult = QuoteResult | ClaimResult;
27	
28	const BASE_PREMIUMS: Record<string, number> = {
29	  sword: 100,
30	  amulet: 60,
31	  staff: 80,
32	  potion: 40,
33	  rune: 25,
34	  moonstone: 25,
35	};
36	
37	const INSURANCE_VALUES: Record<string, number> = {
38	  sword: 1000,
39	  amulet: 600,
40	  staff: 800,
41	  potion: 400,
42	  rune: 250,
43	  moonstone: 250,
44	};
45	
46	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
47	const BLOCK_PREMIUM = 60;
48	const BLOCK_SIZE = 3;
49	
50	const itemSurcharge = (item: Item): number => {
51	  const base = BASE_PREMIUMS[item.type];
52	  const curseSurcharge = item.cursed ? base * CURSE_SURCHARGE : 0;
53	  const enchantSurcharge =
54	    (item.enchantment ?? 0) >= HIGH_ENCHANT_THRESHOLD ? base * HIGH_ENCHANT_SURCHARGE : 0;
55	  return curseSurcharge + enchantSurcharge;
56	};
57	
58	const policyBasePremium = (items: Item[]): number => {
59	  const componentCounts: Record<string, number> = {};
60	  let total = 0;
61	  for (const item of items) {
62	    if (COMPONENT_TYPES.has(item.type)) {
63	      componentCounts[item.type] = (componentCounts[item.type] ?? 0) + 1;
64	    } else {
65	      total += BASE_PREMIUMS[item.type];
66	    }
67	  }
68	  for (const type of Object.keys(componentCounts)) {
69	    const count = componentCounts[type];
70	    if (count === BLOCK_SIZE) {
71	      total += BLOCK_PREMIUM;
72	    } else {
73	      total += count * BASE_PREMIUMS[type];
74	    }
75	  }
76	  return total;
77	};
78	
79	const insuranceSum = (items: Item[]): number =>
80	  items.reduce((sum, item) => sum + INSURANCE_VALUES[item.type], 0);
81	
82	const quote = (items: Item[], customer: Customer, isFollowUp: boolean): QuoteResult => {
83	  const base = policyBasePremium(items);
84	  const surcharges = items.reduce((sum, item) => sum + itemSurcharge(item), 0);
85	  const loyalty = customer.yearsWithMHPCO >= LOYALTY_THRESHOLD ? -base * LOYALTY_DISCOUNT : 0;
86	  const firstInsurance = base * FIRST_INSURANCE_SURCHARGE;
87	  const followUp = isFollowUp ? -base * FOLLOW_UP_DISCOUNT : 0;
88	  const premium = Math.ceil(base + surcharges + loyalty + firstInsurance + followUp + PROCESSING_FEE);
89	  return { premium };
90	};
91	
92	type Policy = {
93	  items: Item[];
94	  remainingCap: number;
95	};
96	
97	const reimbursementRate = (item: Item): number =>
98	  (item.enchantment ?? 0) >= HIGH_ENCHANT_PAYOUT_THRESHOLD
99	    ? HIGH_ENCHANT_REIMBURSEMENT_RATE
100	    : FULL_REIMBURSEMENT_RATE;
101	
102	const damagePayout = (damage: Damage, item: Item): number =>
103	  Math.max(0, damage.amount * reimbursementRate(item) - DEDUCTIBLE);
104	
105	const findInsuredItem = (policy: Policy, damage: Damage): Item | undefined =>
106	  policy.items.find((item) => item.type === damage.itemType);
107	
108	const countByType = (items: { type?: string; itemType?: string }[], key: "type" | "itemType"): Record<string, number> => {
109	  const counts: Record<string, number> = {};
110	  for (const item of items) {
111	    const t = item[key]!;
112	    counts[t] = (counts[t] ?? 0) + 1;
113	  }
114	  return counts;
115	};
116	
117	const validateDamages = (incident: Incident, policy: Policy): void => {
118	  const insuredCounts = countByType(policy.items, "type");
119	  const damageCounts = countByType(incident.damages, "itemType");
120	  for (const type of Object.keys(damageCounts)) {
121	    if ((insuredCounts[type] ?? 0) < damageCounts[type]) {
122	      throw new Error(`Claim has more ${type} damages than insured`);
123	    }
124	  }
125	};
126	
127	const claim = (incident: Incident, policy: Policy): ClaimResult => {
128	  validateDamages(incident, policy);
129	  const grossPayout = incident.damages.reduce((sum, damage) => {
130	    const item = findInsuredItem(policy, damage);
131	    return item ? sum + damagePayout(damage, item) : sum;
132	  }, 0);
133	  const payout = Math.min(grossPayout, policy.remainingCap);
134	  policy.remainingCap -= payout;
135	  return { payout, remainingCap: policy.remainingCap };
136	};
137	
138	export const runScenario = (scenario: Scenario): { results: StepResult[] } => {
139	  let quoteCount = 0;
140	  const policies: Record<number, Policy> = {};
141	  const results: StepResult[] = scenario.steps.map((step, index) => {
142	    if (step.op === "quote") {
143	      const isFollowUp = quoteCount > 0;
144	      quoteCount += 1;
145	      const sum = insuranceSum(step.items);
146	      policies[index] = { items: step.items, remainingCap: sum * 2 };
147	      return quote(step.items, scenario.customer, isFollowUp);
148	    } else {
149	      return claim(step.incident, policies[step.policy]);
150	    }
151	  });
152	  return { results };
153	};
